        const configElem = document.querySelector(`[${ATTR_SKIP_TO_DATA}]`);
        if (configElem) {
          const params = configElem.getAttribute(ATTR_SKIP_TO_DATA);
          this.config  = this.setupConfigFromDataAttribute(this.config, params);
